HRESULT MRFCircumferentialVent::SetBackProfile(const CATBaseUnknown_var &spOnBackProfile)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnPV(_CredentialForCC, this);

	if ((!!FeatFacadeOnPV))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFCircumVent_BackProfile);
		rc = FeatFacadeOnPV.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnPV.UnsetValue(AttrKey);

		if (SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetFeature(spOnBackProfile);

			rc = FeatFacadeOnPV.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;

}

HRESULT MRFCircumferentialVent::GetBackProfile(CATBaseUnknown_var &spOnBackProfile)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnPV(_CredentialForCC, this);

	if (!!FeatFacadeOnPV)
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;
		AttrKey = CATFmAttributeName(_MRFCircumVent_BackProfile);
		rc = FeatFacadeOnPV.GetValue(AttrKey, FmAttrValue);

		if (SUCCEEDED(rc))
		{
			// Get the Curve feature facade
			CATFmFeatureFacade FeatFacadeOnSurface;
			rc = FmAttrValue.GetFeature(FeatFacadeOnSurface);

			if (SUCCEEDED(rc))
				rc = FeatFacadeOnSurface.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)& spOnBackProfile);
		}
	}
	return rc;
}

