HRESULT MRFCircumferentialVent::SetDefaultValuesList(const CATListOfDouble &spOnDefaultGeomSet)
{
	int sizeOfAngRefList = spOnDefaultGeomSet.Size();
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForCC, this);

	if ((sizeOfAngRefList > 0) && (!!FeatFacadeOnGrooveSweep))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValueOnCurve;
		AttrKey = CATFmAttributeName(_MRFCircumVent_DefaultGeomSetValues);
		FeatFacadeOnGrooveSweep.UnsetValue(AttrKey);

		for (int i = 1; i <= sizeOfAngRefList; i++)
		{
			double angleRef = spOnDefaultGeomSet[i];

			CATFmAttributeValue FmAttrValue;
			FmAttrValue.SetDouble(angleRef);

			FmAttrValueOnCurve.Append(FmAttrValue);
		}
		if (FmAttrValueOnCurve.Size() > 0)
		{
			rc = FeatFacadeOnGrooveSweep.SetValue(AttrKey, FmAttrValueOnCurve);
			if (SUCCEEDED(rc))
			{
				//UpdateFeature();
			}
		}
	}
	return rc;
}
HRESULT MRFCircumferentialVent::GetDefaultValuesList(CATListOfDouble &spOnDefaultGeomSet)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGrooveSweep(_CredentialForCC, this);

	CATFmAttributeName AttrKey;
	CATFmAttributeValue FmAttrValueList;
	AttrKey = CATFmAttributeName(_MRFCircumVent_DefaultGeomSetValues);

	if (!!FeatFacadeOnGrooveSweep)
	{
		rc = FeatFacadeOnGrooveSweep.GetValue(AttrKey, FmAttrValueList);

		if (SUCCEEDED(rc))
		{
			int listOfAngRefSize = FmAttrValueList.Size();

			for (int i = 1; i <= listOfAngRefSize; ++i)
			{
				CATFmAttributeValue FmAttrValue;
				rc = FeatFacadeOnGrooveSweep.GetValueAtIndex(AttrKey, i, FmAttrValue);

				if (SUCCEEDED(rc))
				{
					double angleRef;
					if (SUCCEEDED(FmAttrValue.GetDouble(angleRef)))
					{
						spOnDefaultGeomSet.Append(angleRef);
					}
				}
			}
		}
	}
	return rc;

}

